parameters.jsCode:
const raw = $input.first().json.text || "";

// strip markdown fences if Gemini wraps it anyway
const clean = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let intent;
try {
  intent = JSON.parse(clean);
} catch (e) {
  // fallback: treat as a general summary if parsing fails
  intent = {
    intent: "monthly_summary",
    month: null,
    compare_current: true,
    compare_previous: false,
    owner_name: null,
    raw_question: $('Webhook').first().json.body.text || ""
  };
}

// also store the response_url here so every downstream node can access it
intent.response_url = $('Webhook').first().json.body.response_url;
intent.user_name = $('Webhook').first().json.body.user_name || "there";

return [{ json: intent }];

const intent = $('Parse Intent').first().json;

// ── helper functions ──────────────────────────────────────────
function val(deal, field) {
  return deal?.properties?.[field] ?? deal?.[field] ?? null;
}
function num(v) {
  return Number(String(v || 0).replace(/[^0-9.-]/g, "")) || 0;
}
const WON  = ["closedwon", "won", "dealwon"];
const LOST = ["closedlost", "lost", "deallost", "disqualified"];
function isWon(s)  { return WON.some(w  => s?.toLowerCase().includes(w)); }
function isLost(s) { return LOST.some(l => s?.toLowerCase().includes(l)); }

function computeMonth(rawList) {
  const deals = rawList.map(d => ({
    amount:      num(val(d, "amount")),
    stage:       val(d, "dealstage") || "Unknown",
    pipeline:    val(d, "pipeline")  || "Unknown",
    name:        val(d, "dealname")  || "Unnamed",
    owner:       val(d, "hubspot_owner_id") || "Unassigned",
    createdate:  val(d, "createdate"),
    closedate:   val(d, "closedate"),
    lostReason:  val(d, "closed_lost_reason") || null,
    probability: num(val(d, "hs_deal_stage_probability"))
  }));

  const stageSummary    = {};
  const pipelineSummary = {};
  const ownerSummary    = {};
  let wonCount=0, lostCount=0, wonVal=0, lostVal=0, totalVal=0;
  let velocitySum=0, velocityCount=0;
  const lostReasons = {};

  deals.forEach(d => {
    totalVal += d.amount;

    // stage
    if (!stageSummary[d.stage]) stageSummary[d.stage] = { count:0, value:0 };
    stageSummary[d.stage].count += 1;
    stageSummary[d.stage].value += d.amount;

    // pipeline
    if (!pipelineSummary[d.pipeline]) pipelineSummary[d.pipeline] = { count:0, value:0 };
    pipelineSummary[d.pipeline].count += 1;
    pipelineSummary[d.pipeline].value += d.amount;

    // owner
    if (!ownerSummary[d.owner]) ownerSummary[d.owner] = { count:0, value:0 };
    ownerSummary[d.owner].count += 1;
    ownerSummary[d.owner].value += d.amount;

    // won / lost
    if (isWon(d.stage))  { wonCount++;  wonVal  += d.amount; }
    if (isLost(d.stage)) {
      lostCount++;
      lostVal += d.amount;
      if (d.lostReason) {
        lostReasons[d.lostReason] = (lostReasons[d.lostReason] || 0) + 1;
      }
    }

    // deal velocity (days from create to close)
    if (d.createdate && d.closedate) {
      const days = (new Date(d.closedate) - new Date(d.createdate)) / 86400000;
      if (days > 0) { velocitySum += days; velocityCount++; }
    }
  });

  // top 5 deals by value
  const topDeals = [...deals]
    .sort((a, b) => b.amount - a.amount)
    .slice(0, 5)
    .map(d => ({ name: d.name, amount: d.amount, stage: d.stage }));

  return {
    totalDeals: deals.length,
    totalValue: totalVal,
    avgDealValue: deals.length > 0 ? Math.round(totalVal / deals.length) : 0,
    wonCount, lostCount, wonVal, lostVal,
    winRateCount: (wonCount + lostCount) > 0
      ? ((wonCount / (wonCount + lostCount)) * 100).toFixed(1) + "%"
      : "N/A",
    avgVelocityDays: velocityCount > 0
      ? Math.round(velocitySum / velocityCount)
      : null,
    stageSummary,
    pipelineSummary,
    ownerSummary,
    topDeals,
    lostReasons
  };
}

// ── figure out which input is which ──────────────────────────
const allInputs = $input.all();
let currentDeals, previousDeals;

const isComparison = intent.compare_previous === true;

if (isComparison && allInputs.length >= 2) {
  // input[0] = previous month (from Fetch Previous Month)
  // input[1] = current month  (from HTTP Request1)
  const prevRaw = allInputs[0].json.results || [];
  const currRaw = allInputs[1].json.results || [];
  previousDeals = computeMonth(prevRaw);
  currentDeals  = computeMonth(currRaw);
} else {
  const raw = allInputs[0].json.results
    ? allInputs[0].json.results
    : allInputs.map(i => i.json);
  currentDeals  = computeMonth(raw);
  previousDeals = null;
}

// ── build comparison delta ────────────────────────────────────
let comparison = null;
if (previousDeals) {
  const prevWR = parseFloat(previousDeals.winRateCount) || 0;
  const currWR = parseFloat(currentDeals.winRateCount)  || 0;
  comparison = {
    dealCountDelta: currentDeals.totalDeals  - previousDeals.totalDeals,
    valueDelta:     currentDeals.totalValue  - previousDeals.totalValue,
    winRateDelta:   (currWR - prevWR).toFixed(1) + "%",
    valueChangePct: previousDeals.totalValue > 0
      ? (((currentDeals.totalValue - previousDeals.totalValue) / previousDeals.totalValue) * 100).toFixed(1) + "%"
      : "N/A",
    previous: previousDeals,
    current:  currentDeals
  };
}

return [{ json: {
  intent,
  result: currentDeals,
  comparison,
  meta: {
    dealsAnalyzed: currentDeals.totalDeals,
    computedAt: new Date().toISOString()
  }
}}];

parameters.jsonBody:
={{
  (() => {
    const intent = $('Parse Intent').first().json;

    let startDate;
    let endDate;

    if (intent.month) {
      const [yr, mo] = intent.month.split("-").map(Number);
      startDate = new Date(yr, mo - 1, 1);
      endDate = new Date(yr, mo, 0, 23, 59, 59, 999);
    } else {
      const now = new Date();
      startDate = new Date(now.getFullYear(), now.getMonth(), 1);
      endDate = now;
    }

    return {
      filterGroups: [
        {
          filters: [
            {
              propertyName: "createdate",
              operator: "GTE",
              value: startDate.getTime().toString()
            },
            {
              propertyName: "createdate",
              operator: "LTE",
              value: endDate.getTime().toString()
            }
          ]
        }
      ],
      properties: [
  "dealname",
  "amount",
  "createdate",
  "closedate",
  "dealstage",
  "pipeline",
  "hubspot_owner_id",
  "hs_closed_amount",
  "hs_deal_stage_probability",
  "closed_lost_reason"
      ],
      limit: 100
    };
  })()
}}

parameters.jsCode:
const data   = $input.first().json;
const intent = data.intent?.intent || "monthly_summary";
const comp   = data.comparison;

// Only build a chart if the user explicitly asked for comparison
const askedForChart = intent === "comparison";

let chartUrl = null;

if (askedForChart && comp) {
  const config = {
    type: "bar",
    data: {
      labels: ["Previous Month", "Current Month"],
      datasets: [{
        label: "Pipeline Value (BDT)",
        data: [comp.previous.totalValue, comp.current.totalValue],
        backgroundColor: ["#4A90D9", "#27AE60"]
      }]
    },
    options: {
      plugins: { legend: { display: true } },
      scales: { y: { beginAtZero: true } }
    }
  };
  chartUrl = "https://quickchart.io/chart?w=500&h=300&c=" +
    encodeURIComponent(JSON.stringify(config));
}

return [{ json: { ...data, chartUrl } }];
